#include <imgui.h>

void DrawProfessionalDockingWorkspace() {
    static bool show_scene = true;
    static bool show_hierarchy = true;
    static bool show_inspector = true;
    static bool show_console = true;
    static bool show_assets = true;
    static bool compact_mode = false;
    static bool lock_layout = false;
    static int selected_entity = 0;

    ImGuiIO& io = ImGui::GetIO();
    io.ConfigFlags |= ImGuiConfigFlags_DockingEnable;

    ImGui::DockSpaceOverViewport();

    if (ImGui::BeginMainMenuBar()) {
        if (ImGui::BeginMenu("View")) {
            ImGui::MenuItem("Scene", nullptr, &show_scene);
            ImGui::MenuItem("Hierarchy", nullptr, &show_hierarchy);
            ImGui::MenuItem("Inspector", nullptr, &show_inspector);
            ImGui::MenuItem("Console", nullptr, &show_console);
            ImGui::MenuItem("Assets", nullptr, &show_assets);
            ImGui::EndMenu();
        }
        if (ImGui::BeginMenu("Layout")) {
            ImGui::MenuItem("Compact Mode", nullptr, &compact_mode);
            ImGui::MenuItem("Lock Docking", nullptr, &lock_layout);
            ImGui::EndMenu();
        }
        ImGui::EndMainMenuBar();
    }

    if (show_scene) {
        ImGui::Begin("Scene");
        ImGui::Text("Viewport overlay");
        ImGui::Checkbox("Grid", &compact_mode);
        ImGui::Button("Play", ImVec2(84.0f, 0.0f));
        ImGui::SameLine();
        ImGui::Button("Pause", ImVec2(84.0f, 0.0f));
        ImGui::End();
    }

    if (show_hierarchy) {
        ImGui::Begin("Hierarchy");
        if (ImGui::Selectable("Player", selected_entity == 0)) selected_entity = 0;
        if (ImGui::Selectable("Vehicle", selected_entity == 1)) selected_entity = 1;
        if (ImGui::Selectable("Sun Light", selected_entity == 2)) selected_entity = 2;
        ImGui::End();
    }

    if (show_inspector) {
        static float position[3] = {0.0f, 1.2f, -4.0f};
        static float tint[4] = {0.28f, 0.62f, 0.96f, 1.0f};
        ImGui::Begin("Inspector");
        ImGui::Text("Selected entity: %d", selected_entity);
        ImGui::DragFloat3("Position", position, 0.05f);
        ImGui::ColorEdit4("Tint", tint);
        ImGui::End();
    }

    if (show_console) {
        ImGui::Begin("Console");
        ImGui::Text("[Info] Workspace restored.");
        ImGui::Text("[Info] Docking layout synced.");
        ImGui::Text("[Warn] Hot-reload is pending.");
        ImGui::End();
    }

    if (show_assets) {
        ImGui::Begin("Assets");
        ImGui::Text("Meshes");
        ImGui::BulletText("SportsCar.mesh");
        ImGui::BulletText("StreetLamp.mesh");
        ImGui::Text("Textures");
        ImGui::BulletText("GlowMask.png");
        ImGui::BulletText("KeyboardAtlas.png");
        ImGui::End();
    }
}
